import React, { useEffect, useState, useCallback } from "react";
import {
  ActivityIndicator,
  Alert,
  Platform,
  SafeAreaView,
  ScrollView,
  StatusBar,
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
} from "react-native";
import { launchCamera, launchImageLibrary } from "react-native-image-picker";
import { DataLift, isDataLiftAvailable } from "react-native-datalift";
import type { DataLiftResponse } from "react-native-datalift";

// ─── Helpers ──────────────────────────────────────────────────────────────────

const JsonField = ({ label, value }: { label: string; value: unknown }) => {
  const display =
    value === undefined || value === null || value === ""
      ? "—"
      : typeof value === "object"
        ? JSON.stringify(value)
        : String(value);

  return (
    <View style={styles.jsonRow}>
      <Text style={styles.jsonKey}>{label}</Text>
      <Text style={styles.jsonValue} numberOfLines={2}>
        {display}
      </Text>
    </View>
  );
};

const DesignedJsonCard = ({
  title,
  data,
}: {
  title: string;
  data: Record<string, any>;
}) => {
  const header = data?.header ?? {};
  const totals = data?.totals ?? {};
  const vendor = data?.vendor ?? {};
  const audit = data?.audit ?? {};
  const model = audit?.model ?? {};

  return (
    <View style={styles.schemaCard}>
      <Text style={styles.schemaTitle}>{title}</Text>
      <JsonField label="Document Type" value={data?.document_type} />
      <JsonField label="Invoice Number" value={header?.invoice_number} />
      <JsonField label="Receipt Number" value={header?.receipt_number} />
      <JsonField label="Date Issued" value={header?.date_issued} />
      <JsonField label="Vendor" value={vendor?.name} />
      <JsonField label="Grand Total" value={totals?.grand_total} />
      <JsonField label="Amount Due" value={totals?.amount_due} />
      <JsonField label="Model Used" value={model?.layoutlmv3_used} />
      <JsonField label="Model Runtime" value={model?.layoutlmv3_runtime} />

      <Text style={styles.rawLabel}>Full JSON</Text>
      <Text style={styles.rawPreview} numberOfLines={14}>
        {JSON.stringify(data, null, 2)}
      </Text>
    </View>
  );
};

const ResultTile = ({ result }: { result: DataLiftResponse }) => {
  const docType = String(
    result.metadata?.documentType ?? "generic",
  ).toUpperCase();
  const confidence = `${Math.round((result.metadata?.confidenceScore ?? 0) * 100)}%`;
  const total = result.totals?.grandTotal ?? "not found";
  const invoiceNo = result.transaction?.invoiceNumber ?? "not found";
  const lineItems = result.parts?.length ?? 0;

  return (
    <View style={styles.resultCard}>
      <View style={styles.resultTopRow}>
        <Text style={styles.resultType}>{docType}</Text>
        <Text style={styles.badge}>{confidence}</Text>
      </View>
      <Text style={styles.resultMeta}>Invoice/Receipt No: {invoiceNo}</Text>
      <Text style={styles.resultMeta}>Line items: {lineItems}</Text>
      <Text style={styles.resultMeta}>Total: {total}</Text>
      <Text style={styles.rawLabel}>JSON preview</Text>
      <Text style={styles.rawPreview} numberOfLines={8}>
        {JSON.stringify(result, null, 2)}
      </Text>
    </View>
  );
};

// ─── Main App ─────────────────────────────────────────────────────────────────

const App = () => {
  const layoutLMv3ModelPath = "layoutlmv3_invoice.onnx";
  const layoutLMv3LabelsPath = "layoutlmv3_labels.txt";

  const [results, setResults] = useState<DataLiftResponse[]>([]);
  const [schemaResult, setSchemaResult] = useState<Record<
    string,
    unknown
  > | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [modelReady, setModelReady] = useState(false);
  const [modelError, setModelError] = useState<string | null>(null);
  const [compatibility, setCompatibility] = useState<{
    compatible: boolean;
    error?: string;
    warnings?: string[];
  } | null>(null);

  const modelCompatible = compatibility?.compatible === true;

  // ─── Configure LayoutLMv3 on mount ──────────────────────────────────────

  useEffect(() => {
    let active = true;

    const configureModel = async () => {
      try {
        await DataLift.configureLayoutLMv3({
          modelPath: layoutLMv3ModelPath,
          labelsPath: layoutLMv3LabelsPath,
        });
        const compatibilityResult = await DataLift.checkLayoutLMv3Compatibility(
          {
            modelPath: layoutLMv3ModelPath,
            labelsPath: layoutLMv3LabelsPath,
          },
        );

        if (!active) return;
        setCompatibility({
          compatible: compatibilityResult.compatible,
          error: compatibilityResult.error,
          warnings: compatibilityResult.warnings,
        });
        setModelReady(compatibilityResult.compatible);
        setModelError(
          compatibilityResult.compatible
            ? null
            : compatibilityResult.error || "Model compatibility check failed",
        );
      } catch (err) {
        if (!active) return;
        const message = err instanceof Error ? err.message : String(err);
        setModelReady(false);
        setCompatibility({ compatible: false, error: message, warnings: [] });
        setModelError(message);
      }
    };

    configureModel();
    return () => {
      active = false;
    };
  }, [layoutLMv3LabelsPath, layoutLMv3ModelPath]);

  // ─── Core extraction via DataLift.extract() ─────────────────────────────

  const processUri = useCallback(
    async (uri: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await DataLift.extract({
          image: uri,
          language: "eng",
          debug: __DEV__,
        });
        setResults((prev) => [result, ...prev]);
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        setError(msg);
        Alert.alert("Extraction Error", msg);
      } finally {
        setLoading(false);
      }
    },
    [layoutLMv3ModelPath, layoutLMv3LabelsPath],
  );

  // ─── Camera capture ─────────────────────────────────────────────────────

  const handleCapture = useCallback(async () => {
    if (!modelCompatible) {
      Alert.alert(
        "Model Not Ready",
        modelError ?? "Configure a compatible model first.",
      );
      return;
    }
    launchCamera(
      { mediaType: "photo", cameraType: "back", quality: 1 },
      async (response) => {
        if (response.didCancel) return;
        if (response.errorCode) {
          Alert.alert(
            "Camera Error",
            response.errorMessage ?? response.errorCode,
          );
          return;
        }
        const uri = response.assets?.[0]?.uri;
        if (uri) await processUri(uri);
      },
    );
  }, [modelCompatible, modelError, processUri]);

  // ─── Gallery pick ───────────────────────────────────────────────────────

  const handlePick = useCallback(async () => {
    if (!modelCompatible) {
      Alert.alert(
        "Model Not Ready",
        modelError ?? "Configure a compatible model first.",
      );
      return;
    }
    launchImageLibrary(
      { mediaType: "photo", selectionLimit: 5 },
      async (response) => {
        if (response.didCancel) return;
        if (response.errorCode) {
          Alert.alert(
            "Gallery Error",
            response.errorMessage ?? response.errorCode,
          );
          return;
        }
        const uris = (response.assets ?? [])
          .map((a) => a.uri)
          .filter((u): u is string => !!u);
        for (const uri of uris) {
          await processUri(uri);
        }
      },
    );
  }, [modelCompatible, modelError, processUri]);

  // ─── Schema extraction via native model ─────────────────────────────────

  const pickAndExtractSchema = useCallback(async () => {
    if (!modelCompatible) {
      Alert.alert(
        "Model Not Ready",
        modelError ?? "Configure a compatible model first.",
      );
      return;
    }
    try {
      const response = await new Promise<any>((resolve) => {
        launchImageLibrary({ mediaType: "photo", selectionLimit: 4 }, (res) =>
          resolve(res),
        );
      });

      if (response?.didCancel) return;
      if (response?.errorCode) {
        Alert.alert(
          "Picker Error",
          response.errorMessage || response.errorCode,
        );
        return;
      }

      const assets = Array.isArray(response?.assets) ? response.assets : [];
      const uris = assets.map((asset: any) => asset?.uri).filter(Boolean);
      const fileNames = assets
        .map((asset: any) => asset?.fileName)
        .filter(Boolean);

      if (uris.length === 0) {
        Alert.alert("No image", "Please select at least one image.");
        return;
      }

      setLoading(true);
      const result = await DataLift.extractUnifiedSchema({
        imageInput: uris.length === 1 ? uris[0] : uris,
        fileNames,
        language: "eng",
        layoutLMv3ModelPath,
        layoutLMv3LabelsPath,
        requireLayoutLMv3: true,
      });
      setSchemaResult(result);
      const audit = (result?.audit as any) ?? {};
      const model = (audit?.model as any) ?? {};
      const used = model?.layoutlmv3_used === true ? "Yes" : "No";
      Alert.alert("Schema Extracted", `LayoutLMv3 used: ${used}`);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      Alert.alert("LayoutLMv3 Error", message);
    } finally {
      setLoading(false);
    }
  }, [modelCompatible, modelError, layoutLMv3ModelPath, layoutLMv3LabelsPath]);

  // ─── Utility ────────────────────────────────────────────────────────────

  const printLatestJsonToConsole = () => {
    if (results.length === 0 && !schemaResult) {
      Alert.alert("No Results", "Run scan/pick first, then print JSON.");
      return;
    }
    if (results.length > 0) {
      console.log(
        "[DataLift][LatestResult]",
        JSON.stringify(results[0], null, 2),
      );
    }
    if (schemaResult) {
      console.log(
        "[DataLift][LayoutLMv3Schema]",
        JSON.stringify(schemaResult, null, 2),
      );
    }
    Alert.alert("Printed", "Latest JSON printed in Metro console.");
  };

  const clearResults = () => {
    setResults([]);
    setSchemaResult(null);
    setError(null);
  };

  // ─── Render ─────────────────────────────────────────────────────────────

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" backgroundColor="#f8fafc" />
      <ScrollView contentContainerStyle={styles.content}>
        <View style={styles.hero}>
          <Text style={styles.title}>DataLift Example</Text>
          <Text style={styles.subtitle}>
            Core extraction API demo — DataLift.extract() + LayoutLMv3
            on-device.
          </Text>
        </View>

        {!isDataLiftAvailable && (
          <View style={styles.warning}>
            <Text style={styles.warningText}>
              Native module not linked.{" "}
              {Platform.OS === "ios"
                ? "Run pod install + rebuild."
                : "Run a clean Android build."}
            </Text>
          </View>
        )}

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Document Extraction</Text>
          <Text style={styles.sectionText}>
            Uses DataLift.extract() with native OCR + rule-based parser +
            LayoutLMv3 on-device inference.
          </Text>
          <Text style={styles.schemaMeta}>
            Native model: {modelReady ? "configured" : "not configured"}
          </Text>
          <Text style={styles.schemaMeta}>
            Compatibility: {compatibility?.compatible ? "pass" : "fail"}
          </Text>
          {!!compatibility?.warnings?.length && (
            <Text style={styles.schemaMeta}>
              Warning: {compatibility.warnings[0]}
            </Text>
          )}
          {!!modelError && <Text style={styles.errorText}>{modelError}</Text>}

          <View style={styles.buttonRow}>
            <TouchableOpacity
              style={[
                styles.button,
                (loading || !modelCompatible) && styles.buttonDisabled,
              ]}
              disabled={loading || !modelCompatible}
              onPress={handleCapture}
            >
              <Text style={styles.buttonText}>Capture</Text>
            </TouchableOpacity>
            <TouchableOpacity
              style={[
                styles.button,
                styles.buttonSecondary,
                (loading || !modelCompatible) && styles.buttonDisabled,
              ]}
              disabled={loading || !modelCompatible}
              onPress={handlePick}
            >
              <Text style={styles.buttonText}>Pick Images</Text>
            </TouchableOpacity>
          </View>

          <TouchableOpacity
            style={[
              styles.button,
              styles.schemaBtn,
              (loading || !modelCompatible) && styles.buttonDisabled,
            ]}
            disabled={loading || !modelCompatible}
            onPress={pickAndExtractSchema}
          >
            <Text style={styles.buttonText}>Extract Schema (Native Model)</Text>
          </TouchableOpacity>

          {loading && (
            <View style={styles.loadingBox}>
              <ActivityIndicator color="#0ea5e9" />
              <Text style={styles.loadingText}>Processing…</Text>
            </View>
          )}

          {!!error && <Text style={styles.errorText}>{error}</Text>}

          {schemaResult && (
            <DesignedJsonCard
              title="LayoutLMv3 Schema Output"
              data={schemaResult as Record<string, any>}
            />
          )}
        </View>

        <View style={styles.resultsHeader}>
          <Text style={styles.resultsTitle}>Results ({results.length})</Text>
          <View style={styles.resultsActions}>
            <TouchableOpacity
              onPress={printLatestJsonToConsole}
              style={styles.consoleBtn}
            >
              <Text style={styles.consoleBtnText}>JSON Console</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={clearResults} style={styles.clearBtn}>
              <Text style={styles.clearBtnText}>Clear</Text>
            </TouchableOpacity>
          </View>
        </View>

        {results.length === 0 ? (
          <View style={styles.emptyState}>
            <Text style={styles.emptyTitle}>No output yet</Text>
            <Text style={styles.emptyText}>
              Capture or pick an image to see parsed JSON output.
            </Text>
          </View>
        ) : (
          results.map((result, index) => (
            <ResultTile
              key={`${result.metadata?.processingTimeMs}-${index}`}
              result={result}
            />
          ))
        )}
      </ScrollView>
    </SafeAreaView>
  );
};

